+/// Verifies the QE Identity signature against the certificate chain
+pub fn verify_qe_identity_signature(
+    qe_identity: &[u8],
+    signature: &[u8],
+    issuer_chain: &[u8],
+) -> Result<(), Error> {
+    // Parse the certificate chain
+    let certs = parse_certificate_chain(issuer_chain)?;
+    
+    // Verify the chain leads to a trusted root
+    verify_certificate_chain(&certs)?;
+    
+    // Extract the leaf certificate for signature verification
+    let leaf_cert = certs.first().ok_or(Error::InvalidCertificateChain)?;
+    
+    // Verify the signature using the leaf certificate's public key
+    let public_key = extract_public_key(leaf_cert)?;
+    verify_signature(qe_identity, signature, &public_key)?;
+    
+    Ok(())
+}
+
+/// Enforces policy constraints from QE Identity on the QE Report
+pub fn enforce_qe_report_policy(
+    qe_report: &QeReport,
+    qe_identity: &QeIdentityJson,
+) -> Result<(), Error> {
+    // Verify MRSIGNER matches the expected value from QE Identity
+    let expected_mrsigner = &qe_identity.qe_identity.mrsigner;
+    if qe_report.mrsigner != *expected_mrsigner {
+        return Err(Error::QeIdentityMismatch {
+            field: "MRSIGNER",
+            expected: expected_mrsigner.clone(),
+            actual: qe_report.mrsigner.clone(),
+        });
+    }
+    
+    // Verify ISVPRODID matches the expected value
+    let expected_isvprodid = qe_identity.qe_identity.isvprodid;
+    if qe_report.isvprodid != expected_isvprodid {
+        return Err(Error::QeIdentityMismatch {
+            field: "ISVPRODID",
+            expected: expected_isvprodid.to_string(),
+            actual: qe_report.isvprodid.to_string(),
+        });
+    }
