+/**
+ * Validates filesystem URIs to ensure they contain a valid path.
+ * Empty filesystem URIs (e.g., "filesystem://" or "filesystem-v2://") 
+ * can cause resource exhaustion and DoS.
+ */
+export function isValidFileSystemUri(uri: string): boolean {
+	const filesystemPrefixes = ['filesystem://', 'filesystem-v2://'];
+	
+	for (const prefix of filesystemPrefixes) {
+		if (uri.startsWith(prefix)) {
+			const path = uri.slice(prefix.length);
+			// Reject empty paths that could cause DoS
+			return path.length > 0 && path.trim().length > 0;
+		}
+	}
+	
+	return true; // Non-filesystem URIs are valid
+}
